const AdmZip=require("adm-zip");
const f="docs/benchmarks/results/exports/2026-07-03T03-01-24-234Z-daymori-ppt.pptx";
const zip=new AdmZip(f);
const re=/OfficePLUS|CONTENT|LOGO|输入标题|请在此输入|请您单击此处输入文本内容加以解释说明|20XX|时间：202X\/05\/01/i;
const hits=[];
for(const e of zip.getEntries()){
  if(/^ppt\/slides\/slide\d+\.xml$/i.test(e.entryName)){
    const t=e.getData().toString("utf8");
    if(re.test(t)) hits.push(e.entryName);
  }
}
console.log(JSON.stringify({file:f,hitCount:hits.length,hits}, null, 2));
